#nullable enable // autogenerated

using MVZ2.Vanilla.Audios;
using MVZ2Logic.Entities;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using UnityEngine;

namespace MVZ2.GameContent.Bosses
{
    [AutoEntityBehaviourDefinition(VanillaBossNames.pinkWither)]
    public partial class PinkWither : BossBehaviour
    {
        public PinkWither(string nsp, string name) : base(nsp, name)
        {
        }

        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);

            if (entity.IsDead)
                return;

            if (entity.IsTimeInterval(CRY_INTERVAL))
            {
                entity.PlaySound(VanillaSoundID.witherCry, 2);
            }
            entity.Velocity += Vector3.up * 0.1f;
            if (entity.Position.y > 800)
            {
                entity.Remove();
            }
        }
        public const int CRY_INTERVAL = 100;
    }
}
